-- Add masterTeamId column to teams table
ALTER TABLE `teams` ADD COLUMN `masterTeamId` int AFTER `id`;

-- Update teams with master team IDs based on team name
UPDATE `teams` t
SET t.`masterTeamId` = CASE 
  WHEN t.`name` = 'Iron Lions' THEN 1
  WHEN t.`name` = 'Golan Guards' THEN 2
  WHEN t.`name` = 'H Hammers' THEN 3
  WHEN t.`name` = 'Schvitz Saints' THEN 4
  ELSE 1
END
WHERE t.`name` IN ('Iron Lions', 'Golan Guards', 'H Hammers', 'Schvitz Saints');

-- For teams that don't match, assign to Iron Lions (masterTeamId = 1)
UPDATE `teams` SET `masterTeamId` = 1 WHERE `masterTeamId` IS NULL;

-- Make masterTeamId NOT NULL and add foreign key
ALTER TABLE `teams` MODIFY COLUMN `masterTeamId` int NOT NULL;
ALTER TABLE `teams` ADD CONSTRAINT `fk_teams_masterTeamId` FOREIGN KEY (`masterTeamId`) REFERENCES `masterTeams`(`id`) ON DELETE CASCADE;

-- Drop the name and logoUrl columns from teams table since they're now in masterTeams
ALTER TABLE `teams` DROP COLUMN `name`;
ALTER TABLE `teams` DROP COLUMN `logoUrl`;

